ruleContent.content:
@js:
var url = String(baseUrl);
var match = url.match(/\/(\d+)\/(\d+)\.html/);
var content = '';
if (match) {
    var origin = url.match(/(https?:\/\/[^\/]+)/)[1];
    var jsUrl = origin + '/scripts/chapter.js.php?aid=' + match[1] + '&cid=' + match[2] + '&referrer=' + encodeURIComponent(url);
    var scriptStr = java.ajax(jsUrl);
    var token = scriptStr.match(/chapterToken\s*=\s*['"]([^'"]+)['"]/);
    var ts = scriptStr.match(/timestamp\s*=\s*['"]?([^'";\s]+)/);
    var nc = scriptStr.match(/nonce\s*=\s*['"]([^'"]+)['"]/);
    if (token && ts && nc) {
        var ajaxUrl = origin + '/modules/article/ajax2.php?aid=' + match[1] + '&cid=' + match[2] + '&token=' + token[1] + '&timestamp=' + ts[1] + '&nonce=' + nc[1];
        var opt = JSON.stringify({"charset": "gbk", "headers": {"X-Requested-With": "XMLHttpRequest", "Referer": url}});
        var res = java.ajax(ajaxUrl + ',' + opt);
        try {
            content = JSON.parse(res).data.content;
        } catch(e) {}
    }
}
content ? content : java.getString('#rtext@html');

ruleContent.replaceRegex:
@js:
const FILTER_RULES = [
  /更新不易.+?看最新章节！/g,
  /更新不易.+?看最新无错章节！/g, 
  /更新不易.+?最新小说章节！/g,
  /速.?读.?谷/g, 
  /本章节未完.+?请订阅/g,
  /↑返回顶部↑/g,
  /[（(]本章.+?完[）)]/g,
  /^(?=.*[1-9])(?=.*章).+\n/,
]

for(let reg of FILTER_RULES){
	result = result.replace(reg, "")
}
result;

ruleExplore.coverUrl:
class.bookname@a@href
@js:
var m = String(result).match(/\/(\d+)\/?$/);
var id = m ? m[1] : '0';
var p = id.length <= 3 ? '0' : id.slice(0, -3);
return 'https://www.deqixs.cc/files/article/image/' + p + '/' + id + '/' + id + 's.jpg';

ruleExplore.wordCount:
class.author.1@html
@js:
var m = String(result).match(/towan\('(\d+)'\)/);
if(m) { return m[1]; }
return String(result).replace(/<[^>]+>/g, '').replace(/字数[：:]/g, '').trim();

